CREATE TRIGGER [dbo].[PIMS_NUTOUT_A_S_IUD_TR] ON PIMS_NOTIFICATION_USER_OUTPUT FOR INSERT, UPDATE, DELETE AS
SET NOCOUNT ON
BEGIN TRY
DECLARE @curr_date datetime;
SET @curr_date = getutcdate();
  IF NOT EXISTS(SELECT * FROM inserted) AND NOT EXISTS(SELECT * FROM deleted) 
    RETURN;

  -- historical
  IF EXISTS(SELECT * FROM deleted)
    update PIMS_NOTIFICATION_USER_OUTPUT_HIST set END_DATE_HIST = @curr_date where NOTIFICATION_USER_OUTPUT_ID in (select NOTIFICATION_USER_OUTPUT_ID from deleted) and END_DATE_HIST is null;
  
  IF EXISTS(SELECT * FROM inserted)
    insert into PIMS_NOTIFICATION_USER_OUTPUT_HIST ([NOTIFICATION_USER_OUTPUT_ID], [NOTIFICATION_USER_ID], [NOTIFICATION_OUTPUT_TYPE_CODE], [NOTIFICATION_SENT_DT], [NOTIFICATION_READ_DT], [NOTIFICATION_RETRY_CNT], [NOTIFICATION_ERROR_REASON], [NOTIFICATION_ERROR_DT], [CONCURRENCY_CONTROL_NUMBER], [APP_CREATE_TIMESTAMP], [APP_CREATE_USERID], [APP_CREATE_USER_GUID], [APP_CREATE_USER_DIRECTORY], [APP_LAST_UPDATE_TIMESTAMP], [APP_LAST_UPDATE_USERID], [APP_LAST_UPDATE_USER_GUID], [APP_LAST_UPDATE_USER_DIRECTORY], [DB_CREATE_TIMESTAMP], [DB_CREATE_USERID], [DB_LAST_UPDATE_TIMESTAMP], [DB_LAST_UPDATE_USERID], _NOTIFICATION_USER_OUTPUT_HIST_ID, END_DATE_HIST, EFFECTIVE_DATE_HIST)
      select [NOTIFICATION_USER_OUTPUT_ID], [NOTIFICATION_USER_ID], [NOTIFICATION_OUTPUT_TYPE_CODE], [NOTIFICATION_SENT_DT], [NOTIFICATION_READ_DT], [NOTIFICATION_RETRY_CNT], [NOTIFICATION_ERROR_REASON], [NOTIFICATION_ERROR_DT], [CONCURRENCY_CONTROL_NUMBER], [APP_CREATE_TIMESTAMP], [APP_CREATE_USERID], [APP_CREATE_USER_GUID], [APP_CREATE_USER_DIRECTORY], [APP_LAST_UPDATE_TIMESTAMP], [APP_LAST_UPDATE_USERID], [APP_LAST_UPDATE_USER_GUID], [APP_LAST_UPDATE_USER_DIRECTORY], [DB_CREATE_TIMESTAMP], [DB_CREATE_USERID], [DB_LAST_UPDATE_TIMESTAMP], [DB_LAST_UPDATE_USERID], (next value for [dbo].[PIMS_NOTIFICATION_USER_OUTPUT_H_ID_SEQ]) as [_NOTIFICATION_USER_OUTPUT_HIST_ID], null as [END_DATE_HIST], @curr_date as [EFFECTIVE_DATE_HIST] from inserted;

END TRY
BEGIN CATCH
   IF @@trancount > 0 ROLLBACK TRANSACTION
   EXEC pims_error_handling
END CATCH;

