-- Create trigger dbo.PIMS_NOTUSR_I_S_U_TR
PRINT N'Create trigger dbo.PIMS_NOTUSR_I_S_U_TR'
GO
CREATE TRIGGER [dbo].[PIMS_NOTUSR_I_S_U_TR] ON PIMS_NOTIFICATION_USER INSTEAD OF UPDATE AS
SET NOCOUNT ON
BEGIN TRY
  IF NOT EXISTS(SELECT * FROM deleted) 
    RETURN;

  -- validate concurrency control
  if exists (select 1 from inserted, deleted where inserted.CONCURRENCY_CONTROL_NUMBER != deleted.CONCURRENCY_CONTROL_NUMBER+1 AND inserted.NOTIFICATION_USER_ID = deleted.NOTIFICATION_USER_ID)
    raiserror('CONCURRENCY FAILURE.',16,1)


  -- update statement
  update PIMS_NOTIFICATION_USER
    set "NOTIFICATION_USER_ID" = inserted."NOTIFICATION_USER_ID",
      "NOTIFICATION_ID" = inserted."NOTIFICATION_ID",
      "USER_ID" = inserted."USER_ID",
      "CONCURRENCY_CONTROL_NUMBER" = inserted."CONCURRENCY_CONTROL_NUMBER",
      "APP_LAST_UPDATE_TIMESTAMP" = inserted."APP_LAST_UPDATE_TIMESTAMP",
      "APP_LAST_UPDATE_USERID" = inserted."APP_LAST_UPDATE_USERID",
      "APP_LAST_UPDATE_USER_GUID" = inserted."APP_LAST_UPDATE_USER_GUID",
      "APP_LAST_UPDATE_USER_DIRECTORY" = inserted."APP_LAST_UPDATE_USER_DIRECTORY"
    , DB_LAST_UPDATE_TIMESTAMP = getutcdate()
    , DB_LAST_UPDATE_USERID = user_name()
    from PIMS_NOTIFICATION_USER
    inner join inserted
    on (PIMS_NOTIFICATION_USER.NOTIFICATION_USER_ID = inserted.NOTIFICATION_USER_ID);

END TRY
BEGIN CATCH
   IF @@trancount > 0 ROLLBACK TRANSACTION
   EXEC pims_error_handling
END CATCH;

GO
IF @@ERROR <> 0 SET NOEXEC ON
GO

