-- Create trigger dbo.PIMS_NOTIFY_A_S_IUD_TR
PRINT N'Create trigger dbo.PIMS_NOTIFY_A_S_IUD_TR'
GO
CREATE TRIGGER [dbo].[PIMS_NOTIFY_A_S_IUD_TR] ON PIMS_NOTIFICATION FOR INSERT, UPDATE, DELETE AS
SET NOCOUNT ON
BEGIN TRY
DECLARE @curr_date datetime;
SET @curr_date = getutcdate();
  IF NOT EXISTS(SELECT * FROM inserted) AND NOT EXISTS(SELECT * FROM deleted) 
    RETURN;

  -- historical
  IF EXISTS(SELECT * FROM deleted)
    update PIMS_NOTIFICATION_HIST set END_DATE_HIST = @curr_date where NOTIFICATION_ID in (select NOTIFICATION_ID from deleted) and END_DATE_HIST is null;
  
  IF EXISTS(SELECT * FROM inserted)
    insert into PIMS_NOTIFICATION_HIST ([NOTIFICATION_ID], [NOTIFICATION_TYPE_CODE], [ACQUISITION_FILE_ID], [DISPOSITION_FILE_ID], [RESEARCH_FILE_ID], [MANAGEMENT_FILE_ID], [LEASE_ID], [TAKE_ID], [INSURANCE_ID], [LEASE_CONSULTATION_ID], [NOTICE_OF_CLAIM_ID], [LEASE_RENEWAL_ID], [EXPROP_OWNER_HISTORY_ID], [AGREEMENT_ID], [NOTIFICATION_TRIGGER_DATE], [NOTIFICATION_MESSAGE], [CONCURRENCY_CONTROL_NUMBER], [APP_CREATE_TIMESTAMP], [APP_CREATE_USERID], [APP_CREATE_USER_GUID], [APP_CREATE_USER_DIRECTORY], [APP_LAST_UPDATE_TIMESTAMP], [APP_LAST_UPDATE_USERID], [APP_LAST_UPDATE_USER_GUID], [APP_LAST_UPDATE_USER_DIRECTORY], [DB_CREATE_TIMESTAMP], [DB_CREATE_USERID], [DB_LAST_UPDATE_TIMESTAMP], [DB_LAST_UPDATE_USERID], _NOTIFICATION_HIST_ID, END_DATE_HIST, EFFECTIVE_DATE_HIST)
      select [NOTIFICATION_ID], [NOTIFICATION_TYPE_CODE], [ACQUISITION_FILE_ID], [DISPOSITION_FILE_ID], [RESEARCH_FILE_ID], [MANAGEMENT_FILE_ID], [LEASE_ID], [TAKE_ID], [INSURANCE_ID], [LEASE_CONSULTATION_ID], [NOTICE_OF_CLAIM_ID], [LEASE_RENEWAL_ID], [EXPROP_OWNER_HISTORY_ID], [AGREEMENT_ID], [NOTIFICATION_TRIGGER_DATE], [NOTIFICATION_MESSAGE], [CONCURRENCY_CONTROL_NUMBER], [APP_CREATE_TIMESTAMP], [APP_CREATE_USERID], [APP_CREATE_USER_GUID], [APP_CREATE_USER_DIRECTORY], [APP_LAST_UPDATE_TIMESTAMP], [APP_LAST_UPDATE_USERID], [APP_LAST_UPDATE_USER_GUID], [APP_LAST_UPDATE_USER_DIRECTORY], [DB_CREATE_TIMESTAMP], [DB_CREATE_USERID], [DB_LAST_UPDATE_TIMESTAMP], [DB_LAST_UPDATE_USERID], (next value for [dbo].[PIMS_NOTIFICATION_H_ID_SEQ]) as [_NOTIFICATION_HIST_ID], null as [END_DATE_HIST], @curr_date as [EFFECTIVE_DATE_HIST] from inserted;

END TRY
BEGIN CATCH
   IF @@trancount > 0 ROLLBACK TRANSACTION
   EXEC pims_error_handling
END CATCH;

GO
IF @@ERROR <> 0 SET NOEXEC ON
GO

